# Send reminders in the customer's timezone (account tz), DST-aware.
from datetime import datetime, timezone
try:
    from zoneinfo import ZoneInfo  # py3.9+
except ImportError:  # pragma: no cover
    from backports.zoneinfo import ZoneInfo


def _resolve_tz(account):
    tz_name = None
    if isinstance(account, dict):
        tz_name = account.get("timezone") or account.get("tz")
    else:
        tz_name = getattr(account, "timezone", None) or getattr(account, "tz", None)
    if not tz_name:
        return timezone.utc
    try:
        return ZoneInfo(tz_name)
    except Exception:
        return timezone.utc


def localize_reminder(when, account):
    """Convert a reminder timestamp into the customer's account timezone.

    `when` may be a naive or aware datetime; naive is assumed UTC.
    Returns an aware datetime in the customer's tz (DST handled by zoneinfo).
    """
    if when.tzinfo is None:
        when = when.replace(tzinfo=timezone.utc)
    return when.astimezone(_resolve_tz(account))


def handle(value, account=None):
    """Backward-compatible entry point.

    If given a datetime + account, localize the reminder to the customer's tz.
    Otherwise return the value unchanged.
    """
    if isinstance(value, datetime) and account is not None:
        return localize_reminder(value, account)
    return value

